import { _decorator, Component, director, Button, Label } from 'cc';

const { ccclass, property } = _decorator;

@ccclass('LoginSceneSimple')
export class LoginSceneSimple extends Component {
    @property(Button)
    loginBtn: Button = null;
    
    @property(Label)
    titleLabel: Label = null;
    
    onLoad() {
        console.log('LoginSceneSimple onLoad');
        
        if (this.titleLabel) {
            this.titleLabel.string = '财神大陆 - 点击按钮测试';
        }
        
        if (this.loginBtn) {
            this.loginBtn.node.on(Button.EventType.CLICK, this.onClick, this);
            console.log('按钮绑定成功');
        } else {
            console.log('按钮未绑定');
        }
    }
    
    onClick() {
        console.log('按钮被点击！');
        if (this.titleLabel) {
            this.titleLabel.string = '点击成功！游戏正常！';
        }
    }
}
